class Admin_Model_ShippingPayment extends Admin_Model_Base_ShippingPayment {

    public static function clearShippingPayments($shippingID): void {
        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_ShippingPayment')
            ->where('Shipping_ID = ?', $shippingID)
            ->execute();
    }
